sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
   if (isLoading || newValue === '') {
      return;
   }


   var getCompanyN = new GlideAjax('GetCompanyName');
   getCompanyN.addParam('sysparm_name','getCompany');
   getCompanyN.addParam('sysparm_userID', g_form.getValue('u_requested_for'));
   getCompanyN.getXML(populateCompanyName);

	function populateCompanyName(response){

    var companyNameFromScriptInclude = response.responseXML.documentElement.getAttribute("answer");
    g_form.clearValue('u_requested_for_companyName');
    g_form.setValue('u_requested_for_companyName',companyNameFromScriptInclude);
  }
}
